import React, { useState, useEffect } from 'react';
import { currencyService } from '../../services/currencyService';

// Helper function to safely format numbers
const formatNumber = (num) => {
    if (num === null || num === undefined || num === '') {
        return '0.0000';
    }
    const number = typeof num === 'string' ? parseFloat(num) : num;
    if (isNaN(number)) {
        return '0.0000';
    }
    return number.toFixed(4);
};

const PendingApprovals = () => {
    const [pendingChanges, setPendingChanges] = useState([]);
    const [loading, setLoading] = useState(true);
    const [message, setMessage] = useState({ type: '', text: '' });
    const [rejectReason, setRejectReason] = useState({});
    const [expandedCard, setExpandedCard] = useState(null);

    useEffect(() => {
        loadPendingChanges();
    }, []);

    const loadPendingChanges = async () => {
        try {
            setLoading(true);
            const response = await currencyService.getPendingChanges();
            if (response.success) {
                setPendingChanges(response.data || []);
            } else {
                showMessage('error', response.message || 'Failed to load pending changes');
            }
        } catch (error) {
            console.error('Error loading pending changes:', error);
            showMessage('error', error.response?.data?.message || 'Failed to load pending changes');
        } finally {
            setLoading(false);
        }
    };

    const showMessage = (type, text) => {
        setMessage({ type, text });
        setTimeout(() => {
            setMessage({ type: '', text: '' });
        }, 5000);
    };

    const handleApprove = async (changeId) => {
        try {
            const response = await currencyService.approveChange(changeId);
            if (response.success) {
                showMessage('success', 'Change approved successfully');
                loadPendingChanges();
            } else {
                showMessage('error', response.message || 'Failed to approve change');
            }
        } catch (error) {
            console.error('Error approving change:', error);
            showMessage('error', error.response?.data?.message || 'Failed to approve change');
        }
    };

    const handleReject = async (changeId) => {
        const reason = rejectReason[changeId];
        if (!reason || reason.trim() === '') {
            showMessage('error', 'Please provide a rejection reason');
            return;
        }
        
        try {
            const response = await currencyService.rejectChange(changeId, reason);
            if (response.success) {
                showMessage('success', 'Change rejected successfully');
                loadPendingChanges();
                setRejectReason({});
            } else {
                showMessage('error', response.message || 'Failed to reject change');
            }
        } catch (error) {
            console.error('Error rejecting change:', error);
            showMessage('error', error.response?.data?.message || 'Failed to reject change');
        }
    };

    const getChangeTypeIcon = (type) => {
        switch(type) {
            case 'add_currency': return 'fa-plus-circle';
            case 'update_rate': return 'fa-edit';
            case 'delete_currency': return 'fa-trash-alt';
            default: return 'fa-clock';
        }
    };

    const getChangeTypeColor = (type) => {
        switch(type) {
            case 'add_currency': return '#28a745';
            case 'update_rate': return '#ffc107';
            case 'delete_currency': return '#dc3545';
            default: return '#6c757d';
        }
    };

    const getChangeTypeText = (type) => {
        switch(type) {
            case 'add_currency': return 'New Currency Request';
            case 'update_rate': return 'Rate Update Request';
            case 'delete_currency': return 'Deletion Request';
            default: return 'Pending Request';
        }
    };

    const getChangeTypeBadgeColor = (type) => {
        switch(type) {
            case 'add_currency': return '#d4edda';
            case 'update_rate': return '#fff3cd';
            case 'delete_currency': return '#f8d7da';
            default: return '#e2e3e5';
        }
    };

    const getChangeTypeTextColor = (type) => {
        switch(type) {
            case 'add_currency': return '#155724';
            case 'update_rate': return '#856404';
            case 'delete_currency': return '#721c24';
            default: return '#383d41';
        }
    };

    const toggleExpand = (id) => {
        setExpandedCard(expandedCard === id ? null : id);
    };

    if (loading) {
        return (
            <div className="loading-spinner">
                <div className="spinner"></div>
                <p>Loading pending approvals...</p>
            </div>
        );
    }

    if (pendingChanges.length === 0) {
        return (
            <div className="empty-state">
                <i className="fas fa-check-circle"></i>
                <h3>No Pending Approvals</h3>
                <p>All currency change requests have been processed.</p>
                <button onClick={loadPendingChanges} className="btn-secondary" style={{ marginTop: '1rem' }}>
                    <i className="fas fa-sync-alt"></i> Refresh
                </button>
            </div>
        );
    }

    return (
        <div className="pending-approvals">
            <div className="section-header">
                <h2>
                    <i className="fas fa-clock"></i>
                    Pending Approvals
                </h2>
                <span className="badge badge-danger">
                    <i className="fas fa-bell"></i>
                    {pendingChanges.length} pending request{pendingChanges.length !== 1 ? 's' : ''}
                </span>
            </div>

            {message.text && (
                <div className={`message ${message.type}`}>
                    <i className={`fas fa-${message.type === 'success' ? 'check-circle' : 'exclamation-circle'}`}></i>
                    {message.text}
                </div>
            )}

            <div className="pending-list">
                {pendingChanges.map(change => (
                    <div 
                        key={change.id} 
                        className="pending-card"
                        style={{ borderLeftColor: getChangeTypeColor(change.change_type) }}
                    >
                        <div className="pending-header">
                            <div className="pending-type-wrapper">
                                <div 
                                    className="pending-type"
                                    style={{
                                        backgroundColor: getChangeTypeBadgeColor(change.change_type),
                                        color: getChangeTypeTextColor(change.change_type)
                                    }}
                                >
                                    <i className={`fas ${getChangeTypeIcon(change.change_type)}`}></i>
                                    {getChangeTypeText(change.change_type)}
                                </div>
                            </div>
                            <div className="pending-date">
                                <i className="fas fa-calendar-alt"></i>
                                {new Date(change.created_at).toLocaleString()}
                            </div>
                        </div>
                        
                        <div className="pending-details">
                            <div className="detail-row">
                                <strong>Currency:</strong> 
                                <span className="currency-name">{change.currency_name || 'N/A'}</span>
                                <span className="currency-code">({change.currency_code || 'N/A'})</span>
                            </div>
                            
                            {change.sell_rate && change.buy_rate && (
                                <div className="detail-row rate-row">
                                    <strong>New Rates:</strong>
                                    <div className="rate-values">
                                        <span className="sell-rate">
                                            <i className="fas fa-arrow-up"></i> Sell: {formatNumber(change.sell_rate)}
                                        </span>
                                        <span className="buy-rate">
                                            <i className="fas fa-arrow-down"></i> Buy: {formatNumber(change.buy_rate)}
                                        </span>
                                        <span className="spread-rate">
                                            <i className="fas fa-chart-line"></i> Spread: {formatNumber(change.buy_rate - change.sell_rate)}
                                        </span>
                                    </div>
                                </div>
                            )}
                            
                            <div className="detail-row">
                                <strong>Requested by:</strong>
                                <span className="requester">{change.requested_by_name || 'Unknown'}</span>
                            </div>
                            
                            {change.created_at && (
                                <div className="detail-row">
                                    <strong>Requested on:</strong>
                                    <span>{new Date(change.created_at).toLocaleDateString()}</span>
                                </div>
                            )}
                        </div>
                        
                        {change.change_type !== 'delete_currency' && (
                            <div className="preview-section">
                                <div className="preview-header" onClick={() => toggleExpand(change.id)}>
                                    <h4>
                                        <i className={`fas fa-${expandedCard === change.id ? 'chevron-up' : 'chevron-down'}`}></i>
                                        Preview
                                    </h4>
                                </div>
                                {(expandedCard === change.id || pendingChanges.length <= 3) && (
                                    <div className="preview-card">
                                        <div className="preview-icon">
                                            <i className={`fas ${change.currency_icon || 'fa-money-bill-wave'}`}></i>
                                        </div>
                                        <div className="preview-info">
                                            <div className="preview-name">{change.currency_name}</div>
                                            <div className="preview-code">{change.currency_code}</div>
                                            {change.sell_rate && change.buy_rate && (
                                                <div className="preview-rate">
                                                    <span>Sell: {formatNumber(change.sell_rate)}</span>
                                                    <span>Buy: {formatNumber(change.buy_rate)}</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}
                        
                        <div className="reject-section">
                            <textarea
                                placeholder="Rejection reason (required for rejection)..."
                                value={rejectReason[change.id] || ''}
                                onChange={(e) => setRejectReason({...rejectReason, [change.id]: e.target.value})}
                                rows="2"
                                className="reject-textarea"
                            ></textarea>
                        </div>
                        
                        <div className="pending-actions">
                            <button 
                                onClick={() => handleApprove(change.id)} 
                                className="approve-btn"
                            >
                                <i className="fas fa-check-circle"></i>
                                Approve Request
                            </button>
                            <button 
                                onClick={() => handleReject(change.id)} 
                                className="reject-btn"
                            >
                                <i className="fas fa-times-circle"></i>
                                Reject Request
                            </button>
                        </div>
                    </div>
                ))}
            </div>
            
            <div className="pending-footer">
                <button onClick={loadPendingChanges} className="refresh-btn">
                    <i className="fas fa-sync-alt"></i>
                    Refresh List
                </button>
            </div>
        </div>
    );
};

export default PendingApprovals;
